from flask import Flask, request, jsonify
import face_recognition
import numpy as np

app = Flask(__name__)

# Load employee photos and encode them
employee_photos = [
    "path_to_employee1.jpg",
    "path_to_employee2.jpg",
    # Add more paths here
]
employee_encodings = [face_recognition.face_encodings(face_recognition.load_image_file(photo))[0] for photo in employee_photos]

@app.route('/recognize', methods=['POST'])
def recognize_face():
    if 'image' not in request.files:
        return jsonify({"error": "No image provided"}), 400

    image = request.files['image']
    face_encoding = face_recognition.face_encodings(face_recognition.load_image_file(image))[0]

    # Compare the new face encoding with all employee encodings
    distances = [face_recognition.face_distance([employee_encoding], face_encoding)[0] for employee_encoding in employee_encodings]
    min_distance = np.min(distances)
    confidence_scores = 1 - distances / np.max(distances)

    if min_distance < 0.6:  # Adjust threshold as needed
        return jsonify({"confidence": confidence_scores.tolist(), "employee_index": np.argmin(distances)})
    else:
        return jsonify({"confidence": confidence_scores.tolist(), "employee_index": None})

if __name__ == '__main__':
    app.run(host='0.0.0.0', port=5000)